INSERT INTO notices (title, category, author, department, publish_date, summary, content) VALUES
('关于2025年12月学院党委理论学习中心组学习的通知', '党委通知', '计算机学院党委', '计算机学院党委', '2025-12-03 10:00:00', '2025年12月计算机学院党委理论学习中心组学习安排', '<p>各党支部：</p><p>现将2025年12月计算机学院党委理论学习中心组学习安排通知如下：</p><h3>学习主题</h3><p>深入学习贯彻党的二十大精神，推动学院高质量发展</p><h3>学习时间</h3><p>2025年12月10日（星期三）上午9:00-11:30</p><h3>学习地点</h3><p>学院会议室（科技楼301）</p><h3>参加人员</h3><p>学院党委理论学习中心组成员、各党支部书记</p><p>请相关人员提前做好准备，准时参加学习。</p><p>计算机学院党委</p><p>2025年12月3日</p>'),
('关于举办2025年计算机学院"学党章、强党性"知识竞赛的通知', '活动通知', '计算机学院团委', '计算机学院团委', '2025-11-30 14:00:00', '为深入学习贯彻习近平新时代中国特色社会主义思想，举办"学党章、强党性"知识竞赛', '<p>各团支部：</p><p>为深入学习贯彻习近平新时代中国特色社会主义思想，引导广大团员青年认真学习党章、严格遵守党章、切实贯彻党章、坚决维护党章，学院团委决定举办2025年"学党章、强党性"知识竞赛。现将有关事项通知如下：</p><h3>参赛对象</h3><p>全院团员青年</p><h3>比赛时间</h3><p>2025年12月15日（星期一）晚上19:00-21:00</p><h3>比赛地点</h3><p>学院学术报告厅</p><h3>报名方式</h3><p>请各团支部于12月10日前将参赛名单报至学院团委办公室。</p><p>联系人：李老师</p><p>联系电话：8888-8888</p><p>计算机学院团委</p><p>2025年11月30日</p>'),
('关于2025年计算机学院教师年度考核工作的通知', '人事通知', '计算机学院人事处', '计算机学院人事处', '2025-12-01 09:30:00', '2025年计算机学院教师年度考核工作安排', '<p>各位教师：</p><p>现将2025年计算机学院教师年度考核工作有关事项通知如下：</p><h3>考核对象</h3><p>全院在编在岗教师</p><h3>考核内容</h3><p>1. 思想政治表现</p><p>2. 教学工作</p><p>3. 科研工作</p><p>4. 社会服务</p><p>5. 其他工作</p><h3>考核时间</h3><p>2025年12月5日至12月20日</p><h3>考核要求</h3><p>请各位教师认真填写《年度考核登记表》，并准备相关支撑材料。</p><p>计算机学院人事处</p><p>2025年12月1日</p>'),
('关于计算机学院2026年硕士研究生招生工作的通知', '招生通知', '计算机学院研究生办公室', '计算机学院研究生办公室', '2025-11-25 16:00:00', '2026年计算机学院硕士研究生招生工作安排', '<p>各位考生：</p><p>现将2026年计算机学院硕士研究生招生工作有关事项通知如下：</p><h3>招生专业</h3><p>1. 计算机科学与技术</p><p>2. 软件工程</p><p>3. 人工智能</p><h3>报名时间</h3><p>2025年12月10日至12月31日</p><h3>考试时间</h3><p>2026年3月15日至3月16日</p><h3>咨询方式</h3><p>电话：8888-8889</p><p>邮箱：graduate@computer.edu.cn</p><p>计算机学院研究生办公室</p><p>2025年11月25日</p>'),
('关于开展计算机学院2025年"党员示范岗"评选活动的通知', '党委通知', '计算机学院党委', '计算机学院党委', '2025-12-02 11:00:00', '为充分发挥党员先锋模范作用，开展"党员示范岗"评选活动', '<p>各党支部：</p><p>为深入学习贯彻党的二十大精神，充分发挥党员先锋模范作用，激励广大党员立足岗位、创先争优，学院党委决定开展2025年"党员示范岗"评选活动。现将有关事项通知如下：</p><h3>评选范围</h3><p>全院在职党员</p><h3>评选条件</h3><p>1. 政治素质高</p><p>2. 业务能力强</p><p>3. 工作业绩突出</p><p>4. 群众评价好</p><h3>申报时间</h3><p>2025年12月5日至12月12日</p><h3>评选程序</h3><p>1. 个人申报</p><p>2. 支部推荐</p><p>3. 学院评审</p><p>4. 公示表彰</p><p>计算机学院党委</p><p>2025年12月2日</p>'),
('关于计算机学院实验室安全检查的通知', '安全通知', '计算机学院实验室管理中心', '计算机学院实验室管理中心', '2025-12-04 09:00:00', '为加强实验室安全管理，开展实验室安全检查', '<p>各实验室：</p><p>为加强实验室安全管理，消除安全隐患，保障师生生命财产安全，学院实验室管理中心决定开展实验室安全检查。现将有关事项通知如下：</p><h3>检查时间</h3><p>2025年12月8日（星期一）上午9:00-11:30</p><h3>检查范围</h3><p>全院所有教学、科研实验室</p><h3>检查内容</h3><p>1. 实验室安全制度执行情况</p><p>2. 安全设施设备运行情况</p><p>3. 危险化学品管理情况</p><p>4. 用电安全情况</p><p>5. 消防安全情况</p><h3>工作要求</h3><p>请各实验室提前做好自查工作，并准备相关材料。</p><p>计算机学院实验室管理中心</p><p>2025年12月4日</p>'),
('关于举办计算机学院2025年"青春向党"主题演讲比赛的通知', '活动通知', '计算机学院团委', '计算机学院团委', '2025-11-27 15:00:00', '为庆祝中国共产党成立104周年，举办"青春向党"主题演讲比赛', '<p>各团支部：</p><p>为庆祝中国共产党成立104周年，引导广大团员青年坚定理想信念，听党话、跟党走，学院团委决定举办2025年"青春向党"主题演讲比赛。现将有关事项通知如下：</p><h3>参赛对象</h3><p>全院团员青年</p><h3>演讲主题</h3><p>青春向党，奋斗强国</p><h3>比赛时间</h3><p>2025年12月20日（星期六）下午14:00-17:00</p><h3>比赛地点</h3><p>学院学术报告厅</p><h3>报名方式</h3><p>请各团支部于12月15日前将参赛名单报至学院团委办公室。</p><p>计算机学院团委</p><p>2025年11月27日</p>'),
('关于计算机学院2025年冬季运动会的通知', '活动通知', '计算机学院体育教学部', '计算机学院体育教学部', '2025-11-29 10:30:00', '2025年计算机学院冬季运动会安排', '<p>各位师生：</p><p>为丰富师生课余生活，增强体质，学院体育教学部决定举办2025年冬季运动会。现将有关事项通知如下：</p><h3>活动时间</h3><p>2025年12月22日（星期一）至12月24日（星期三）</p><h3>活动地点</h3><p>学院体育场</p><h3>参赛对象</h3><p>全院师生</p><h3>比赛项目</h3><p>1. 个人项目：100米、200米、400米、800米、1500米、跳远、跳高、铅球等</p><p>2. 集体项目：4×100米接力、拔河、跳长绳等</p><h3>报名方式</h3><p>请各系部、各班级于12月15日前将参赛名单报至学院体育教学部。</p><p>计算机学院体育教学部</p><p>2025年11月29日</p>');
